// ─── NIK ENGINE ──────────────────────────────────────────────
const NIK={
  parse(nik){
    const s=nik.replace(/\D/g,"");
    if(s.length!==16)return{valid:false,error:"NIK harus 16 digit"};
    const provCode=s.slice(0,2),kabCode=s.slice(0,4),kecCode=s.slice(0,6);
    const dd=parseInt(s.slice(6,8)),mm=parseInt(s.slice(8,10)),yy=parseInt(s.slice(10,12));
    const isFemale=dd>40;const day=isFemale?dd-40:dd;
    if(day<1||day>31||mm<1||mm>12)return{valid:false,error:"Tanggal lahir tidak valid"};
    const prov=PROV[provCode];
    if(!prov)return{valid:false,error:`Kode provinsi ${provCode} tidak dikenali`};
    const year=yy>50?1900+yy:2000+yy;
    const birthDate=`${year}-${String(mm).padStart(2,"0")}-${String(day).padStart(2,"0")}`;
    const gender=isFemale?"female":"male";
    const coords=PROV_COORDS[provCode]||null;
    return{valid:true,nik:s,provinsi:prov,provCode,kabCode,kecCode,birthDate,gender,day,month:mm,year,coords,masked:`${s.slice(0,6)}••••••${s.slice(12)}`};
  },
  mask(nik){const s=(nik||"").replace(/\D/g,"");return s.length===16?`${s.slice(0,6)}••••••${s.slice(12)}`:nik||"";},
  validate(nik){return NIK.parse(nik).valid;}
};
