function autoLayout(pp){const roots=pp.filter(p=>!p.parentId&&!pp.some(x=>x.spouseId===p.id&&x.parentId));const pos={};function lay(pid,d){const p=pp.find(x=>x.id===pid);if(!p||pos[pid])return{x:0,w:0};const sp=FE.sp(pp,p);const ch=FE.ch(pp,pid);const cw=sp?CW*2+CG:CW;if(!ch.length){pos[pid]={x:0,y:d*(CH+GY)};if(sp&&!pos[sp.id])pos[sp.id]={x:CW+CG,y:d*(CH+GY)};return{x:0,w:cw}}const cls=[];let cur=0;ch.forEach(c=>{const cl=lay(c.id,d+1);cls.push({...cl,offset:cur});cur+=cl.w+GX});const tcw=cur-GX;const cx=(cls[0].offset+cls[cls.length-1].offset+cls[cls.length-1].w)/2-cw/2;const px=Math.max(0,cx);pos[pid]={x:px,y:d*(CH+GY)};if(sp&&!pos[sp.id])pos[sp.id]={x:px+CW+CG,y:d*(CH+GY)};const cbx=px+cw/2-tcw/2;ch.forEach((c,i)=>shift(c.id,cbx+cls[i].offset));return{x:Math.min(px,cbx),w:Math.max(px+cw,cbx+tcw)-Math.min(px,cbx)}}function shift(pid,dx){if(!pos[pid])return;pos[pid].x+=dx;const sp=FE.sp(pp,pp.find(x=>x.id===pid));if(sp&&pos[sp.id])pos[sp.id].x+=dx;FE.ch(pp,pid).forEach(c=>shift(c.id,dx))}let gc=0;roots.forEach(root=>{lay(root.id,0);const sa=pid=>{if(pos[pid])pos[pid].x+=gc;const sp=FE.sp(pp,pp.find(x=>x.id===pid));if(sp&&pos[sp.id])pos[sp.id].x+=gc;FE.ch(pp,pid).forEach(c=>sa(c.id))};sa(root.id);let mxX=0;Object.values(pos).forEach(p=>mxX=Math.max(mxX,p.x));gc=mxX+CW+GX*3});let mnX=Infinity,mnY=Infinity;Object.values(pos).forEach(p=>{mnX=Math.min(mnX,p.x);mnY=Math.min(mnY,p.y)});Object.values(pos).forEach(p=>{p.x-=mnX-100;p.y-=mnY-80});return pos}
function getConns(pp,pos){const L=[];pp.forEach(p=>{const ps=pos[p.id];if(!ps)return;const sp=FE.sp(pp,p);if(sp&&pos[sp.id]&&p.id<sp.id)L.push({t:"sp",x1:ps.x+CW,y1:ps.y+CH/2,x2:pos[sp.id].x,y2:ps.y+CH/2});const ch=FE.ch(pp,p.id);if(ch.length){const cw=sp&&pos[sp.id]?(pos[sp.id].x+CW-ps.x):CW;const pcx=ps.x+cw/2,pb=ps.y+CH;const ct=ch.map(c=>{const cp=pos[c.id];if(!cp)return null;const cs=FE.sp(pp,c);const ccw=cs&&pos[cs.id]?(pos[cs.id].x+CW-cp.x):CW;return{cx:cp.x+ccw/2,y:cp.y}}).filter(Boolean);if(ct.length){const my=pb+GY/2;L.push({t:"pd",x1:pcx,y1:pb,x2:pcx,y2:my});if(ct.length>1)L.push({t:"br",x1:Math.min(...ct.map(c=>c.cx)),y1:my,x2:Math.max(...ct.map(c=>c.cx)),y2:my});ct.forEach(c=>L.push({t:"cd",x1:c.cx,y1:my,x2:c.cx,y2:c.y}))}}});return L}
